impl RingComputeBackend for CpuBackend {
    fn name(&self) -> &'static str {
        "cpu"
    }

    fn upload_f32_dataset(
        &mut self,
        dims: usize,
        vectors: Vec<f32>,
        norms_sq: Vec<f32>,
    ) -> Result<()> {
        self.dims = dims;
        self.n_vectors = norms_sq.len();
        self.vectors = vectors;
        self.norms_sq = norms_sq;
        Ok(())
    }

    fn ring_query_f32(&self, dims: usize, query: &[f32], d_min: f32, d_max: f32) -> Result<Vec<u32>> {
        if self.n_vectors == 0 {
            return Ok(Vec::new());
        }
        if query.len() != dims {
            return Err(RingDbError::DimensionMismatch {
                expected: dims,
                got: query.len(),
            });
        }

        let norm_sq_q = norm_sq_f32(query);
        let lower_sq = d_min * d_min;
        let upper_sq = d_max * d_max;

        let ids: Vec<u32> = self
            .vectors
            .par_chunks_exact(dims)
            .zip(self.norms_sq.par_iter())
            .enumerate()
            .filter_map(|(i, (row, &norm_sq_i))| {
                let dot = dot_f32(row, query);
                let dist_sq = norm_sq_i + norm_sq_q - 2.0 * dot;
                (dist_sq >= lower_sq && dist_sq <= upper_sq).then_some(i as u32)
            })
            .collect();
        Ok(ids)
    }
}

use crate::error::Result;

pub mod cpu;

pub use cpu::CpuBackend;

/// Trait implemented by all compute backends.
///
/// The separation between upload and query reflects the core performance
/// design: the dataset is uploaded once, then many queries run against
/// the resident data without re-uploading.
pub trait RingComputeBackend: Send + Sync {
    /// Human-readable backend name (e.g. `"cpu"`).
    fn name(&self) -> &'static str;

    /// Upload a float32 dataset to the backend.
    ///
    /// - `dims`: number of dimensions per vector.
    /// - `vectors`: flat row-major buffer, length `n * dims`.
    /// - `norms_sq`: precomputed squared L2 norm per vector, length `n`.
    ///
    /// Ownership is transferred: the backend decides whether to keep or
    /// consume the data (e.g. a GPU backend would copy to VRAM and drop).
    fn upload_f32_dataset(
        &mut self,
        dims: usize,
        vectors: Vec<f32>,
        norms_sq: Vec<f32>,
    ) -> Result<()>;

    /// Execute a float32 ring search.
    ///
    /// Returns IDs of all vectors with Euclidean distance to `query` in
    /// `[d - lambda, d + lambda]`.
    fn ring_query_f32(&self, dims: usize, query: &[f32], d: f32, lambda: f32) -> Result<Vec<u32>>;
}

use crate::error::Result;

pub mod cpu;

pub use cpu::CpuBackend;

/// Trait implemented by all compute backends.
///
/// The separation between upload and query reflects the core performance
/// design: the dataset is uploaded once, then many queries run against
/// the resident data without re-uploading.
pub trait RingComputeBackend: Send + Sync {
    /// Human-readable backend name (e.g. `"cpu"`).
    fn name(&self) -> &'static str;

    /// Upload a float32 dataset to the backend.
    ///
    /// - `dims`: number of dimensions per vector.
    /// - `vectors`: flat row-major buffer, length `n * dims`.
    /// - `norms_sq`: precomputed squared L2 norm per vector, length `n`.
    ///
    /// Ownership is transferred: the backend decides whether to keep or
    /// consume the data (e.g. a GPU backend would copy to VRAM and drop).
    fn upload_f32_dataset(
        &mut self,
        dims: usize,
        vectors: Vec<f32>,
        norms_sq: Vec<f32>,
    ) -> Result<()>;

    /// Execute a float32 range search.
    ///
    /// Returns IDs of all vectors with Euclidean distance to `query` in
    /// `[d_min, d_max]`.
    fn ring_query_f32(&self, dims: usize, query: &[f32], d_min: f32, d_max: f32) -> Result<Vec<u32>>;
}

use std::time::Duration;

/// A ring query: find all vectors whose Euclidean distance to `query`
/// lies within `[d - lambda, d + lambda]`.
///
/// Internally, ringdb uses squared L2 distances to avoid computing square
/// roots. The ring bounds become:
///
/// ```text
/// lower_sq = max(0, d - lambda)²
/// upper_sq = (d + lambda)²
/// ```
pub struct RingQuery<'a> {
    /// The query vector. Must have length equal to `RingDb::dims()`.
    pub query: &'a [f32],
    /// Target distance (centre of the ring).
    pub d: f32,
    /// Half-width of the ring.
    pub lambda: f32,
}

/// Result of a ring query.
pub struct QueryResult {
    /// IDs of all vectors whose distance to the query falls within
    /// `[d - lambda, d + lambda]`. IDs correspond to insertion order
    /// (first inserted vector has ID 0).
    pub ids: Vec<u32>,
    /// Name of the backend that executed the query (e.g. `"cpu"`, `"wgpu"`, `"cuda"`).
    pub backend_used: &'static str,
    /// Wall-clock time for the query (excluding dataset upload).
    pub elapsed: Duration,
}

use std::time::Duration;

/// A ring query: find all vectors whose Euclidean distance to `query`
/// lies within `[d - lambda, d + lambda]`.
///
/// Internally, ringdb uses squared L2 distances to avoid computing square
/// roots. The ring bounds become:
///
/// ```text
/// lower_sq = max(0, d - lambda)²
/// upper_sq = (d + lambda)²
/// ```
pub struct RingQuery<'a> {
    /// The query vector. Must have length equal to `RingDb::dims()`.
    pub query: &'a [f32],
    /// Target distance (centre of the ring).
    pub d: f32,
    /// Half-width of the ring.
    pub lambda: f32,
}

/// A range query: find all vectors whose Euclidean distance to `query`
/// lies within `[d_min, d_max]`.
pub struct RangeQuery<'a> {
    /// The query vector. Must have length equal to `RingDb::dims()`.
    pub query: &'a [f32],
    /// Lower bound of the distance interval (inclusive). Must be ≥ 0.
    pub d_min: f32,
    /// Upper bound of the distance interval (inclusive). Must be ≥ `d_min`.
    pub d_max: f32,
}

/// A disk query: find all vectors whose Euclidean distance to `query`
/// is at most `d_max` (i.e. the full disk/ball of radius `d_max`).
///
/// This is equivalent to a [`RangeQuery`] with `d_min = 0`.
pub struct DiskQuery<'a> {
    /// The query vector. Must have length equal to `RingDb::dims()`.
    pub query: &'a [f32],
    /// Radius of the disk (inclusive upper bound on distance). Must be ≥ 0.
    pub d_max: f32,
}

/// Result of a ring query.
pub struct QueryResult {
    /// IDs of all vectors whose distance to the query falls within
    /// `[d - lambda, d + lambda]`. IDs correspond to insertion order
    /// (first inserted vector has ID 0).
    pub ids: Vec<u32>,
    /// Name of the backend that executed the query (e.g. `"cpu"`, `"wgpu"`, `"cuda"`).
    pub backend_used: &'static str,
    /// Wall-clock time for the query (excluding dataset upload).
    pub elapsed: Duration,
}

// ringdb — exact float32 ring search shader
//
// Each thread handles one vector.
// Computes: dist_sq = norm_sq[i] + norm_sq_q - 2 * dot(vectors[i], query)
// Sets a bit in the output bitmask if lower_sq <= dist_sq <= upper_sq.
//
// Output is a packed bitmask: output[vid/32] bit (vid%32) = 1 means hit.

struct Params {
    n_vectors  : u32,
    dims       : u32,
    lower_sq   : f32,
    upper_sq   : f32,
    norm_sq_q  : f32,
    vid_offset : u32,   // global vector-ID offset for this chunk
    _pad1      : u32,
    _pad2      : u32,
}

@group(0) @binding(0) var<uniform>            params   : Params;
@group(0) @binding(1) var<storage, read>      vectors  : array<f32>;
@group(0) @binding(2) var<storage, read>      norms_sq : array<f32>;
@group(0) @binding(3) var<storage, read>      query    : array<f32>;
@group(0) @binding(4) var<storage, read_write> output  : array<atomic<u32>>;

@compute @workgroup_size(256, 1, 1)
fn main(@builtin(global_invocation_id) gid: vec3<u32>) {
    let vid: u32 = gid.x;          // local index into this chunk
    if vid >= params.n_vectors {
        return;
    }

    var dot: f32 = 0.0;
    let base: u32 = vid * params.dims;
    for (var j: u32 = 0u; j < params.dims; j = j + 1u) {
        dot = dot + vectors[base + j] * query[j];
    }

    let dist_sq: f32 = norms_sq[vid] + params.norm_sq_q - 2.0 * dot;

    if dist_sq >= params.lower_sq && dist_sq <= params.upper_sq {
        let global_vid: u32 = params.vid_offset + vid;
        let word: u32 = global_vid / 32u;
        let bit:  u32 = global_vid % 32u;
        atomicOr(&output[word], 1u << bit);
    }
}

// ringdb — exact float32 ring search shader
//
// Each thread handles one vector.
// Computes: dist_sq = norm_sq[i] + norm_sq_q - 2 * dot(vectors[i], query)
// Sets a bit in the output bitmask if lower_sq <= dist_sq <= upper_sq.
//
// Output is a packed bitmask: output[vid/32] bit (vid%32) = 1 means hit.
//
// Dispatch uses a 2-D grid (X × Y) to exceed the 65 535 workgroup-per-
// dimension limit.  The flat vector index is:
//     vid = gid.y * (num_workgroups.x * 256) + gid.x

struct Params {
    n_vectors  : u32,
    dims       : u32,
    lower_sq   : f32,
    upper_sq   : f32,
    norm_sq_q  : f32,
    vid_offset : u32,   // global vector-ID offset for this chunk
    _pad1      : u32,
    _pad2      : u32,
}

@group(0) @binding(0) var<uniform>            params   : Params;
@group(0) @binding(1) var<storage, read>      vectors  : array<f32>;
@group(0) @binding(2) var<storage, read>      norms_sq : array<f32>;
@group(0) @binding(3) var<storage, read>      query    : array<f32>;
@group(0) @binding(4) var<storage, read_write> output  : array<atomic<u32>>;

@compute @workgroup_size(256, 1, 1)
fn main(
    @builtin(global_invocation_id) gid: vec3<u32>,
    @builtin(num_workgroups)       nwg: vec3<u32>,
) {
    let vid: u32 = gid.y * (nwg.x * 256u) + gid.x;
    if vid >= params.n_vectors {
        return;
    }

    var dot: f32 = 0.0;
    let base: u32 = vid * params.dims;
    for (var j: u32 = 0u; j < params.dims; j = j + 1u) {
        dot = dot + vectors[base + j] * query[j];
    }

    let dist_sq: f32 = norms_sq[vid] + params.norm_sq_q - 2.0 * dot;

    if dist_sq >= params.lower_sq && dist_sq <= params.upper_sq {
        let global_vid: u32 = params.vid_offset + vid;
        let word: u32 = global_vid / 32u;
        let bit:  u32 = global_vid % 32u;
        atomicOr(&output[word], 1u << bit);
    }
}
